sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        // If the requester is cleared, you may want to remove the old info too
        if (newValue === '') {
            var descToClear = g_form.getValue('description') || '';
            var clearedDesc = descToClear.split('\n\nRequester Company:')[0];
            g_form.setValue('description', clearedDesc.trim());
        }
        return;
    }

    var ga = new GlideAjax('UserDetailFetcher');
    ga.addParam('sysparm_name', 'getDisplayValues');
    ga.addParam('sysparm_user_id', newValue);
    ga.getXMLAnswer(function(response) {
        if (response) {
            var user = JSON.parse(response);

            // 1. Get current description
            var currentDesc = g_form.getValue('description') || '';

            // 2. Remove the OLD requester block if it exists
            // This splits the text at the start of our custom block and keeps only what's before it
            var cleanDesc = currentDesc.split('\n\nRequester Company:')[0].trim();

            // 3. Create the new block
            var additionalInfo = '\n\nRequester Company: ' + user.company +
                                 '\nRequester Email: ' + user.email +
                                 '\nRequester Mobile Phone: ' + user.mobile +
                                 '\nRequester Department: ' + user.department +
                                 '\nRequester Title: ' + user.title;

            // 4. Set the value with only the original text + the SINGLE new block
            g_form.setValue('description', cleanDesc + additionalInfo);
        }
    });
}
